        set<pair<int, int>> travel;
        travel.insert(make_pair(y, x));
        bfs(maze, x, y, lowestt, xmax, ymax, 0, travel); // Start with 0 turns
        return (lowestt == 99999) ? -1 : lowestt;
    }

private:
    void bfs(vector<vector<char>>& maze, int x, int y, int& lowestt, int xmax, int ymax, int turns, set<pair<int, int>>& travel) {
        if (!travel.contains(make_pair(y, x)) && (x == 0 || x == xmax - 1 || y == 0 || y == ymax - 1)) {
